import{_ as i,o as t,c as l,ag as r}from"./chunks/framework.DXGyWiRo.js";const a="/images/lekt5501.jpg",c=JSON.parse('{"title":"Lektion 55","description":"","frontmatter":{},"headers":[],"relativePath":"lektionen/lektion55.md","filePath":"lektionen/lektion55.md"}'),n={name:"lektionen/lektion55.md"};function o(s,e,d,u,h,p){return t(),l("div",null,[...e[0]||(e[0]=[r('<div class="info custom-block github-alert"><p class="custom-block-title">Zitierweise &amp; Rechte</p><p>Dieses Kapitel ist Teil des Sanskritkurses. Details zum Copyright und zur Zitierweise der Ursprungsfassung siehe: <a href="/impressum">Impressum &amp; Copyright</a></p></div><h1 id="lektion-55" tabindex="-1">Lektion 55 <a class="header-anchor" href="#lektion-55" aria-label="Permalink to &quot;Lektion 55&quot;">​</a></h1><h2 id="ubersicht" tabindex="-1">Übersicht <a class="header-anchor" href="#ubersicht" aria-label="Permalink to &quot;Übersicht&quot;">​</a></h2><ul><li>55.1. Der a-Aorist (Aorist mit Themavokal)</li><li>55.2. Übung</li></ul><h2 id="_55-1-der-a-aorist-aorist-mit-themavokal" tabindex="-1">55.1. Der a-Aorist (Aorist mit Themavokal) <a class="header-anchor" href="#_55-1-der-a-aorist-aorist-mit-themavokal" aria-label="Permalink to &quot;55.1. Der a-Aorist (Aorist mit Themavokal)&quot;">​</a></h2><p>Der a-Aorist wird gebildet wie ein Imperfekt (लङ्) der 6. Präsensklasse (तुदादि), d.h.:</p><p>Augment + tiefstufige Wurzel + a + Sekundärendung</p><p>Das -a- wird in den gleichen Fällen wie im Imperfekt durch -ā- ersetzt.</p><p>Keine Nasalinfixe.</p><p>Das Ātmanepada ist selten; zu Ubhayapadawurzeln wird es meist nach anderen Aoristklassen gebildet (sieje Kielhorn, Grammatik §340 sowie unten bei den entsprechenden Aoristklassen).</p><p>Liste der Wurzeln, die diesen Aorist haben, bei Kielhorn, Grammatik §340.</p><p>Beispiel:</p><p>सिच् 6U &quot;beträufeln&quot;</p><blockquote><table tabindex="0"><thead><tr><th></th><th>परस्मैपदम्</th><th>आत्मनेपदम्</th></tr></thead><tbody><tr><td></td><td>एकवचनम्</td><td>बहुवचनम्</td></tr><tr><td>1. तृतीयः</td><td>असिचम्</td><td>असिचाम</td></tr><tr><td>2. मध्यमः</td><td>असिचस्</td><td>असिचत</td></tr><tr><td>3. प्रथमः</td><td>असिचत्</td><td>असिचन्</td></tr></tbody></table></blockquote><p>Unregelmäßige Bildungen:</p><blockquote><p>अस् 4P &quot;werfen&quot;: आस्थम्, आस्थत् (Erklärung siehe Thumb-Hauschild §541,4)</p><p>ख्या + आ 2P &quot;erzählen&quot;: अख्यम्, अख्यत्</p><p>दृश् &quot;sehen&quot;: अदर्शम्, अदर्शत् (Hochstufe!)</p></blockquote><p>Beachte:</p><blockquote><p>शास् 2P &quot;befehlen&quot;: अशिषत् (regelmäßige Tiefstufe!)</p></blockquote><h2 id="_55-2-ubung" tabindex="-1">55.2. Übung <a class="header-anchor" href="#_55-2-ubung" aria-label="Permalink to &quot;55.2. Übung&quot;">​</a></h2><p>Bestimmen und übersetzen Sie schriftlich folgende formen und bilden Sie die entsprechenden Formen des a-Aorist:</p><ol><li>दोक्ष्यन्ति</li><li>बुबोध</li><li>क्रुध्यसि</li><li>तोक्ष्यथ</li><li>कुप्यामः</li><li>आप</li><li>जग्मुः</li><li>छेत्स्यसि</li><li>पश्यथ</li><li>ध्रोक्ष्यामि</li><li>नेश</li><li>भिन्त्थ</li><li>भ्राम्यामः</li><li>मुञ्चति</li><li>मुह्यसि</li><li>अरोदीत्</li><li>रुरोधिथ</li><li>श्राम्यन्ति</li><li>विन्दथ</li><li>असीदन्</li><li>वर्तामहे (a-Aor.: P)</li><li>अशात्</li><li>सेक्ष्यसे</li><li>अयुनक्</li><li>आरिथ</li><li>अक्लिद्यन्</li><li>अजीर्यम् (Aor.: hochstufig)</li><li>लुम्पति</li><li>अशाम्यत</li><li>अशोभथाः  (a-Aor.: P)</li><li>अशुष्याम</li><li>सिष्णेह</li></ol><p><img src="'+a+'" alt=""><br> Abb.: अजीर्यमिति<br> &#39;Inâyat Khân am Sterben, Entwurf für eine Miniatur einer Handschrift für Jahângîr = جهانگير, um 1618<br> [Bildquelle: <a href="http://zeno.org/Kunstwerke/B/Meister+der+Mogul-Schule+um+1618:+Sterbender?hl=inayat+khan" target="_blank" rel="noreferrer">http://zeno.org/Kunstwerke/B/Meister+der+Mogul-Schule+um+1618%3A+Sterbender?hl=inayat+khan</a>. -- Zugriff am 2009-01-28. Gemeinfrei]</p>',22)])])}const b=i(n,[["render",o]]);export{c as __pageData,b as default};
